//! Numerical parity tests against the onnxruntime reference (NFR-QL-01).
//!
//! Fixtures live in `tests/parity/silero_vad/` and are regenerated by
//! `gen_reference.py` (see that directory's README). Ground truth is
//! onnxruntime running the upstream `silero_vad.onnx`; our GGUF weights come
//! from the same ONNX, so ORT is a faithful oracle.
//!
//! Coverage:
//! * per-stage, first frame / zero state (from lifted `If`-branch ORT graphs):
//!   pseudo-STFT conv (T04), magnitude (T05), encoder output (T06);
//! * single-frame end-to-end probability (T07);
//! * multi-frame streaming with LSTM state carry-over, both rates (T09).
//!
//! FP32 tolerance is `atol = 0.01` (NFR-QL-01). The stage references are ORT
//! float32 tensors; small accumulation-order differences stay well inside it.

use vokra_core::engines::VadEngine;
use vokra_core::gguf::GgufFile;

use super::encoder::encode;
use super::pseudo_stft::{pseudo_stft, stft_conv};
use super::wav::read_wav_f32;
use super::weights::SileroWeights;
use super::{SampleRate, SileroVadV5, parity_dir, test_gguf_path};

/// FP32 numerical parity tolerance (NFR-QL-01).
const ATOL: f32 = 0.01;

fn tag(rate: SampleRate) -> &'static str {
    match rate {
        SampleRate::Hz8000 => "8k",
        SampleRate::Hz16000 => "16k",
    }
}

/// Reads a whitespace/newline-separated float fixture (locale-independent
/// `str::parse`, never `strtod` — NFR-RL-01).
fn read_floats(name: &str) -> Vec<f32> {
    let path = parity_dir().join(name);
    let text = std::fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("read fixture {}: {e}", path.display()));
    text.split_whitespace()
        .map(|t| {
            t.parse::<f32>()
                .unwrap_or_else(|e| panic!("parse `{t}` in {name}: {e}"))
        })
        .collect()
}

fn max_abs_err(a: &[f32], b: &[f32]) -> f32 {
    assert_eq!(
        a.len(),
        b.len(),
        "length mismatch: {} vs {}",
        a.len(),
        b.len()
    );
    a.iter()
        .zip(b)
        .map(|(x, y)| (x - y).abs())
        .fold(0.0f32, f32::max)
}

fn load_weights() -> SileroWeights {
    let gguf = GgufFile::open(test_gguf_path()).expect("load fixture gguf");
    SileroWeights::from_gguf(&gguf).expect("bind weights")
}

/// First fixed-size frame of the rate's test WAV (the zero-state step input).
fn first_frame(rate: SampleRate) -> Vec<f32> {
    let wav = read_wav_f32(parity_dir().join(format!("test_{}.wav", tag(rate)))).unwrap();
    assert_eq!(wav.sample_rate, rate.hz());
    wav.samples[..rate.frame_len()].to_vec()
}

fn stage_test(rate: SampleRate) {
    let w = load_weights();
    let rw = w.rate(rate).expect("rate present in fixture gguf");
    let frame = first_frame(rate);

    // T04: pseudo-STFT conv output.
    let (conv, _frames) = stft_conv(rate, rw, &frame);
    let conv_ref = read_floats(&format!("step_stftconv_{}.txt", tag(rate)));
    let conv_err = max_abs_err(&conv, &conv_ref);
    assert!(
        conv_err < ATOL,
        "{} stft conv err {conv_err} >= {ATOL}",
        tag(rate)
    );

    // T05: magnitude.
    let mag = pseudo_stft(rate, rw, &frame);
    let mag_ref = read_floats(&format!("step_magnitude_{}.txt", tag(rate)));
    let mag_err = max_abs_err(&mag.data, &mag_ref);
    assert!(
        mag_err < ATOL,
        "{} magnitude err {mag_err} >= {ATOL}",
        tag(rate)
    );

    // T06: encoder output.
    let enc = encode(rw, &mag);
    let enc_ref = read_floats(&format!("step_encoder_{}.txt", tag(rate)));
    let enc_err = max_abs_err(&enc.data, &enc_ref);
    assert!(
        enc_err < ATOL,
        "{} encoder err {enc_err} >= {ATOL}",
        tag(rate)
    );

    eprintln!(
        "[silero parity {}] stft_conv={conv_err:.2e} magnitude={mag_err:.2e} encoder={enc_err:.2e}",
        tag(rate)
    );
}

/// e2e streaming parity: push the whole WAV, compare every frame probability to
/// the ORT reference with LSTM state carried across frames.
fn stream_test(rate: SampleRate) {
    let model = SileroVadV5::open(test_gguf_path()).unwrap();
    let wav = read_wav_f32(parity_dir().join(format!("test_{}.wav", tag(rate)))).unwrap();
    assert_eq!(wav.sample_rate, rate.hz());

    let mut stream = model.open_stream();
    let probs = stream.push_pcm(&wav.samples, rate.hz()).unwrap();
    let reference = read_floats(&format!("probs_{}.txt", tag(rate)));
    assert_eq!(probs.len(), reference.len(), "{} frame count", tag(rate));

    let err = max_abs_err(&probs, &reference);
    eprintln!(
        "[silero parity {}] e2e streaming frames={} max_abs_err={err:.3e} (atol={ATOL})",
        tag(rate),
        probs.len()
    );
    assert!(err < ATOL, "{} e2e prob err {err} >= {ATOL}", tag(rate));

    // T07: single frame (fresh state) equals the first streaming frame.
    let single = model
        .forward_chunk(rate, &wav.samples[..rate.frame_len()])
        .unwrap();
    assert!(
        (single - reference[0]).abs() < ATOL,
        "{} single-chunk",
        tag(rate)
    );
}

#[test]
fn stage_parity_16k() {
    stage_test(SampleRate::Hz16000);
}

#[test]
fn stage_parity_8k() {
    stage_test(SampleRate::Hz8000);
}

#[test]
fn vad_stream_parity_16k() {
    stream_test(SampleRate::Hz16000);
}

#[test]
fn vad_stream_parity_8k() {
    stream_test(SampleRate::Hz8000);
}
